"""Launch Interceptor Program — DECIDE logic (Knight & Leveson, 1986)."""

from __future__ import annotations

import math
from typing import Any, Dict, List, Tuple

PI = 3.1415926535


def realcompare(a: float, b: float) -> str:
    """Compare two reals using six significant digits; return LT, EQ, or GT."""

    def _quantize(x: float) -> float:
        if x == 0.0:
            return 0.0
        e = math.floor(math.log10(abs(x)))
        return round(x, int(5 - e))

    qa = _quantize(a)
    qb = _quantize(b)
    if qa < qb:
        return "LT"
    if qa > qb:
        return "GT"
    return "EQ"


def _lt(a: float, b: float) -> bool:
    return realcompare(a, b) == "LT"


def _le(a: float, b: float) -> bool:
    return realcompare(a, b) != "GT"


def _gt(a: float, b: float) -> bool:
    return realcompare(a, b) == "GT"


def _eq(a: float, b: float) -> bool:
    return realcompare(a, b) == "EQ"


def _dist(x1: float, y1: float, x2: float, y2: float) -> float:
    return math.hypot(x2 - x1, y2 - y1)


def _min_enclosing_circle_radius_3(
    x1: float, y1: float, x2: float, y2: float, x3: float, y3: float
) -> float:
    """Minimum radius of a circle containing three points (planar)."""
    d12 = _dist(x1, y1, x2, y2)
    d23 = _dist(x2, y2, x3, y3)
    d13 = _dist(x1, y1, x3, y3)
    cp = (x2 - x1) * (y3 - y1) - (x3 - x1) * (y2 - y1)
    if _eq(abs(cp), 0.0):
        return max(d12, d23, d13) * 0.5
    r_circ = (d12 * d23 * d13) / (2.0 * abs(cp))
    d12_2 = d12 * d12
    d23_2 = d23 * d23
    d13_2 = d13 * d13
    # Obtuse at p1 (opposite d23)
    if _lt(d12_2 + d13_2, d23_2):
        return d23 * 0.5
    # Obtuse at p2 (opposite d13)
    if _lt(d12_2 + d23_2, d13_2):
        return d13 * 0.5
    # Obtuse at p3 (opposite d12)
    if _lt(d13_2 + d23_2, d12_2):
        return d12 * 0.5
    return r_circ


def _triangle_area(x1: float, y1: float, x2: float, y2: float, x3: float, y3: float) -> float:
    return abs((x2 - x1) * (y3 - y1) - (x3 - x1) * (y2 - y1)) * 0.5


def _quadrant(px: float, py: float) -> int:
    """Quadrant I–IV with axis tie-breaking per spec."""
    if _eq(px, 0.0) and _eq(py, 0.0):
        return 1
    if _gt(px, 0.0) and _gt(py, 0.0):
        return 1
    if _lt(px, 0.0) and _gt(py, 0.0):
        return 2
    if _lt(px, 0.0) and _lt(py, 0.0):
        return 3
    if _gt(px, 0.0) and _lt(py, 0.0):
        return 4
    if _eq(py, 0.0) and _gt(px, 0.0):
        return 1
    if _eq(py, 0.0) and _lt(px, 0.0):
        return 2
    if _eq(px, 0.0) and _gt(py, 0.0):
        return 1
    if _eq(px, 0.0) and _lt(py, 0.0):
        return 3
    return 1


def _angle_at_vertex(
    vx: float,
    vy: float,
    ax: float,
    ay: float,
    bx: float,
    by: float,
) -> float | None:
    """Interior angle [0, PI] at vertex V between VA and VB; None if undefined."""
    v1x, v1y = ax - vx, ay - vy
    v2x, v2y = bx - vx, by - vy
    if _eq(v1x, 0.0) and _eq(v1y, 0.0):
        return None
    if _eq(v2x, 0.0) and _eq(v2y, 0.0):
        return None
    n1 = math.hypot(v1x, v1y)
    n2 = math.hypot(v2x, v2y)
    c = (v1x * v2x + v1y * v2y) / (n1 * n2)
    if _lt(c, -1.0):
        c = -1.0
    elif _gt(c, 1.0):
        c = 1.0
    return math.acos(c)


def _point_to_line_distance(
    px: float,
    py: float,
    x1: float,
    y1: float,
    x2: float,
    y2: float,
) -> float:
    """Perpendicular distance from P to infinite line through (x1,y1)-(x2,y2)."""
    dx, dy = x2 - x1, y2 - y1
    if _eq(dx, 0.0) and _eq(dy, 0.0):
        return _dist(px, py, x1, y1)
    num = abs(dy * px - dx * py + x2 * y1 - y2 * x1)
    den = math.hypot(dx, dy)
    return num / den


def _lic1(x: List[float], y: List[float], n: int, length1: float) -> bool:
    for i in range(n - 1):
        d = _dist(x[i], y[i], x[i + 1], y[i + 1])
        if _gt(d, length1):
            return True
    return False


def _lic2(x: List[float], y: List[float], n: int, radius1: float) -> bool:
    for i in range(n - 2):
        r = _min_enclosing_circle_radius_3(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2])
        if _gt(r, radius1):
            return True
    return False


def _lic3(x: List[float], y: List[float], n: int, epsilon: float) -> bool:
    low = PI - epsilon
    high = PI + epsilon
    for i in range(n - 2):
        ang = _angle_at_vertex(x[i + 1], y[i + 1], x[i], y[i], x[i + 2], y[i + 2])
        if ang is None:
            continue
        if _lt(ang, low) or _gt(ang, high):
            return True
    return False


def _lic4(x: List[float], y: List[float], n: int, area1: float) -> bool:
    for i in range(n - 2):
        a = _triangle_area(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2])
        if _gt(a, area1):
            return True
    return False


def _lic5(x: List[float], y: List[float], n: int, q_pts: int, quads: int) -> bool:
    for s in range(n - q_pts + 1):
        seen = set()
        for j in range(s, s + q_pts):
            seen.add(_quadrant(x[j], y[j]))
        if len(seen) > quads:
            return True
    return False


def _lic6(x: List[float], y: List[float], n: int) -> bool:
    for i in range(n - 1):
        if _lt(x[i + 1] - x[i], 0.0):
            return True
    return False


def _lic7(x: List[float], y: List[float], n: int, n_pts: int, dist_param: float) -> bool:
    if n < 3:
        return False
    for s in range(n - n_pts + 1):
        x1, y1 = x[s], y[s]
        x2, y2 = x[s + n_pts - 1], y[s + n_pts - 1]
        if _eq(x1, x2) and _eq(y1, y2):
            for k in range(s, s + n_pts):
                d0 = _dist(x[k], y[k], x1, y1)
                if _gt(d0, dist_param):
                    return True
        else:
            for k in range(s, s + n_pts):
                d0 = _point_to_line_distance(x[k], y[k], x1, y1, x2, y2)
                if _gt(d0, dist_param):
                    return True
    return False


def _lic8(x: List[float], y: List[float], n: int, k_pts: int, length1: float) -> bool:
    if n < 3:
        return False
    for i in range(n - k_pts - 1):
        d = _dist(x[i], y[i], x[i + k_pts + 1], y[i + k_pts + 1])
        if _gt(d, length1):
            return True
    return False


def _lic9(x: List[float], y: List[float], n: int, a_pts: int, b_pts: int, radius1: float) -> bool:
    if n < 5:
        return False
    span = a_pts + b_pts + 2
    for i in range(n - span - 1 + 1):
        r = _min_enclosing_circle_radius_3(
            x[i], y[i],
            x[i + a_pts + 1], y[i + a_pts + 1],
            x[i + a_pts + b_pts + 2], y[i + a_pts + b_pts + 2],
        )
        if _gt(r, radius1):
            return True
    return False


def _lic10(x: List[float], y: List[float], n: int, c_pts: int, d_pts: int, epsilon: float) -> bool:
    if n < 5:
        return False
    low = PI - epsilon
    high = PI + epsilon
    span = c_pts + d_pts + 2
    for i in range(n - span - 1 + 1):
        vx, vy = x[i + c_pts + 1], y[i + c_pts + 1]
        ang = _angle_at_vertex(vx, vy, x[i], y[i], x[i + c_pts + d_pts + 2], y[i + c_pts + d_pts + 2])
        if ang is None:
            continue
        if _lt(ang, low) or _gt(ang, high):
            return True
    return False


def _lic11(x: List[float], y: List[float], n: int, e_pts: int, f_pts: int, area1: float) -> bool:
    if n < 5:
        return False
    span = e_pts + f_pts + 2
    for i in range(n - span - 1 + 1):
        a = _triangle_area(
            x[i], y[i],
            x[i + e_pts + 1], y[i + e_pts + 1],
            x[i + e_pts + f_pts + 2], y[i + e_pts + f_pts + 2],
        )
        if _gt(a, area1):
            return True
    return False


def _lic12(x: List[float], y: List[float], n: int, g_pts: int) -> bool:
    if n < 3:
        return False
    for i in range(n - g_pts - 1):
        if _lt(x[i + g_pts + 1] - x[i], 0.0):
            return True
    return False


def _lic13(x: List[float], y: List[float], n: int, k_pts: int, length1: float, length2: float) -> bool:
    if n < 3:
        return False
    has_gt = False
    has_lt = False
    for i in range(n - k_pts - 1):
        d = _dist(x[i], y[i], x[i + k_pts + 1], y[i + k_pts + 1])
        if _gt(d, length1):
            has_gt = True
        if _lt(d, length2):
            has_lt = True
        if has_gt and has_lt:
            return True
    return False


def _lic14(x: List[float], y: List[float], n: int, a_pts: int, b_pts: int, radius1: float, radius2: float) -> bool:
    if n < 5:
        return False
    span = a_pts + b_pts + 2
    has_gt = False
    has_le = False
    for i in range(n - span - 1 + 1):
        r = _min_enclosing_circle_radius_3(
            x[i], y[i],
            x[i + a_pts + 1], y[i + a_pts + 1],
            x[i + a_pts + b_pts + 2], y[i + a_pts + b_pts + 2],
        )
        if _gt(r, radius1):
            has_gt = True
        if _le(r, radius2):
            has_le = True
        if has_gt and has_le:
            return True
    return False


def _lic15(x: List[float], y: List[float], n: int, e_pts: int, f_pts: int, area1: float, area2: float) -> bool:
    if n < 5:
        return False
    span = e_pts + f_pts + 2
    has_gt = False
    has_lt = False
    for i in range(n - span - 1 + 1):
        a = _triangle_area(
            x[i], y[i],
            x[i + e_pts + 1], y[i + e_pts + 1],
            x[i + e_pts + f_pts + 2], y[i + e_pts + f_pts + 2],
        )
        if _gt(a, area1):
            has_gt = True
        if _lt(a, area2):
            has_lt = True
        if has_gt and has_lt:
            return True
    return False


def decide(
    numpoints: int,
    x: List[float],
    y: List[float],
    parameters: Dict[str, Any],
    lcm: List[List[str]],
    pum_diag: List[bool],
) -> Tuple[List[bool], List[List[bool]], List[bool], bool]:
    """
    Behaviorally equivalent to DECIDE. Returns (cmv, pum, fuv, launch).
    Python index i corresponds to LIC (i+1) in the specification.
    """
    n = numpoints
    p = parameters

    length1 = float(p["LENGTH1"])
    radius1 = float(p["RADIUS1"])
    epsilon = float(p["EPSILON"])
    area1 = float(p["AREA1"])
    q_pts = int(p["Q_PTS"])
    quads = int(p["QUADS"])
    dist_p = float(p["DIST"])
    n_pts = int(p["N_PTS"])
    k_pts = int(p["K_PTS"])
    a_pts = int(p["A_PTS"])
    b_pts = int(p["B_PTS"])
    c_pts = int(p["C_PTS"])
    d_pts = int(p["D_PTS"])
    e_pts = int(p["E_PTS"])
    f_pts = int(p["F_PTS"])
    g_pts = int(p["G_PTS"])
    length2 = float(p["LENGTH2"])
    radius2 = float(p["RADIUS2"])
    area2 = float(p["AREA2"])

    cmv = [
        _lic1(x, y, n, length1),
        _lic2(x, y, n, radius1),
        _lic3(x, y, n, epsilon),
        _lic4(x, y, n, area1),
        _lic5(x, y, n, q_pts, quads),
        _lic6(x, y, n),
        _lic7(x, y, n, n_pts, dist_p),
        _lic8(x, y, n, k_pts, length1),
        _lic9(x, y, n, a_pts, b_pts, radius1),
        _lic10(x, y, n, c_pts, d_pts, epsilon),
        _lic11(x, y, n, e_pts, f_pts, area1),
        _lic12(x, y, n, g_pts),
        _lic13(x, y, n, k_pts, length1, length2),
        _lic14(x, y, n, a_pts, b_pts, radius1, radius2),
        _lic15(x, y, n, e_pts, f_pts, area1, area2),
    ]

    pum: List[List[bool]] = [[False] * 15 for _ in range(15)]
    for i in range(15):
        pum[i][i] = pum_diag[i]

    for i in range(15):
        for j in range(15):
            if i == j:
                continue
            conn = lcm[i][j]
            if conn == "NOTUSED":
                pum[i][j] = True
            elif conn == "ANDD":
                pum[i][j] = cmv[i] and cmv[j]
            elif conn == "ORR":
                pum[i][j] = cmv[i] or cmv[j]
            else:
                pum[i][j] = False

    fuv: List[bool] = []
    for i in range(15):
        row_all = all(pum[i][k] for k in range(15))
        fuv.append((not pum_diag[i]) or row_all)

    launch = all(fuv)

    return (cmv, pum, fuv, launch)
